Greedy cost-aware insertion with fallback seed assignment using saved state and full enumeration of feasible slots across all existing and potential new assigns.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		newAssign bool
	}
	const INF_COST = 1e18
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for jj := 0; jj < orderCount; jj++ {
		bestCand := candidate{-1, INF_COST, false}
		shipID := total_ship + jj
		ori := oris[jj]
		des := dess[jj]
		maxExisting := dispatch.AssignsLen
		totalChecks := maxExisting
		if maxExisting < MAXASSIGNS {
			totalChecks++
		}
		for tryIdx := 0; tryIdx < totalChecks; tryIdx++ {
			isNewSlot := (tryIdx >= maxExisting)
			var assignIdx int
			if isNewSlot {
				assignIdx = maxExisting
			} else {
				assignIdx = tryIdx
			}
			currentAssign := &dispatch.Assigns[assignIdx]
			savedStateExists := currentAssign.StationsLen > 0
			var savedCost float64
			if savedStateExists {
				savedCost = currentAssign.Cost
			}
			ok := currentAssign.AddShip(shipID, ori, des)
			if ok {
				currentAssign.GenRoute()
				insertCost := currentAssign.Cost
				validInsertion := (insertCost >= 0)
				if validInsertion {
					delta := insertCost - savedCost
					if isNewSlot {
						delta = insertCost
					}
					if delta < bestCand.costDelta {
						bestCand.assignIdx = assignIdx
						bestCand.costDelta = delta
						bestCand.newAssign = isNewSlot
					}
				}
			}
			currentAssign.RemoveShip(shipID)
			if savedStateExists || (!isNewSlot && currentAssign.StationsLen == 0) {
				currentAssign.GenRoute()
			} else {
				currentAssign.Cost = 0
			}
		}
		finalIdx := bestCand.assignIdx
		isFallback := false
		if finalIdx < 0 {
			fallbackIdx := 0
			if dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			finalIdx = fallbackIdx
			isFallback = true
		}
		targetAssign := &dispatch.Assigns[finalIdx]
		if isFallback {
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
				if finalIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			} else {
				targetAssign.RemoveShip(shipID)
				targetAssign.GenRoute()
			}
		} else {
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
				if bestCand.newAssign && finalIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			} else {
				targetAssign.RemoveShip(shipID)
				targetAssign.GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

